// src/app/guards/auth-guard.ts
function waitForRol(auth2) {
  return auth2.rol$.pipe(filter((r) => r !== null), take(1));
}
var authGuard = () => {
  const auth2 = inject2(AuthService);
  const router = inject2(Router);
  return auth2.usuario$.pipe(take(1), switchMap((user) => {
    if (!user) {
      router.navigate(["/login"]);
      return [false];
    }
    return [true];
  }));
};
var adminGuard = () => {
  const auth2 = inject2(AuthService);
  const router = inject2(Router);
  return auth2.usuario$.pipe(take(1), switchMap((user) => {
    if (!user) {
      router.navigate(["/login"]);
      return [false];
    }
    return waitForRol(auth2).pipe(map((rol) => {
      if (rol !== "admin") {
        router.navigate(["/menu"]);
        return false;
      }
      return true;
    }));
  }));
};
var cocinaGuard = () => {
  const auth2 = inject2(AuthService);
  const router = inject2(Router);
  return auth2.usuario$.pipe(take(1), switchMap((user) => {
    if (!user) {
      router.navigate(["/login"]);
      return [false];
    }
    return waitForRol(auth2).pipe(map((rol) => {
      if (rol !== "cocina") {
        router.navigate(["/login"]);
        return false;
      }
      return true;
    }));
  }));
};
var deliveryGuard = () => {
  const auth2 = inject2(AuthService);
  const router = inject2(Router);
  return auth2.usuario$.pipe(take(1), switchMap((user) => {
    if (!user) {
      router.navigate(["/login"]);
      return [false];
    }
    return waitForRol(auth2).pipe(map((rol) => {
      if (rol !== "delivery" && rol !== "admin") {
        router.navigate(["/menu"]);
        return false;
      }
      return true;
    }));
  }));
};

