(() => {
  (typeof ngDevMode === "undefined" || ngDevMode) && setClassMetadata(CheckoutComponent, [{
    type: Component,
    args: [{ selector: "app-checkout", standalone: true, imports: [CommonModule, FormsModule, TranslateModule, BolivianoCurrencyPipe, MapPickerComponent], template: `<div style="min-height:100vh;background:#f8faf8;padding:24px;font-family:'Segoe UI',sans-serif">\r
  <div style="max-width:980px;margin:0 auto">\r
    <div style="display:flex;align-items:center;justify-content:space-between;gap:12px;margin-bottom:20px">\r
      <div>\r
        <h1 style="margin:0;font-size:28px;color:#0f172a">{{ 'CHECKOUT.TITLE' | translate }}</h1>\r
        <p style="margin:6px 0 0;color:#64748b;font-size:14px">{{ 'CHECKOUT.SUBTITLE' | translate }}</p>\r
      </div>\r
      <button type="button" (click)="volverAMenu()" style="border:1px solid #d1d5db;background:white;border-radius:10px;padding:10px 14px;cursor:pointer">\r
        {{ 'CHECKOUT.BACK_TO_MENU' | translate }}\r
      </button>\r
    </div>\r
\r
    <div style="display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:10px;margin-bottom:18px">\r
      <div [style]="paso === 'resumen' ? 'padding:10px;border-radius:12px;background:#dcfce7;color:#166534;font-size:13px;font-weight:700;text-align:center' : 'padding:10px;border-radius:12px;background:#e2e8f0;color:#334155;font-size:13px;text-align:center'">1. {{ 'CHECKOUT.STEP_CART' | translate }}</div>\r
      <div [style]="paso === 'confirmacion' ? 'padding:10px;border-radius:12px;background:#dcfce7;color:#166534;font-size:13px;font-weight:700;text-align:center' : 'padding:10px;border-radius:12px;background:#e2e8f0;color:#334155;font-size:13px;text-align:center'">2. {{ 'CHECKOUT.STEP_CONFIRM' | translate }}</div>\r
      <div [style]="paso === 'resultado' ? 'padding:10px;border-radius:12px;background:#dcfce7;color:#166534;font-size:13px;font-weight:700;text-align:center' : 'padding:10px;border-radius:12px;background:#e2e8f0;color:#334155;font-size:13px;text-align:center'">3. {{ 'CHECKOUT.STEP_RESULT' | translate }}</div>\r
    </div>\r
\r
    <div *ngIf="errorCheckout" style="margin-bottom:14px;padding:10px 12px;background:#fef2f2;color:#b91c1c;border:1px solid #fecaca;border-radius:10px;font-size:13px">\r
      {{ errorCheckout }}\r
    </div>\r
\r
    <div *ngIf="avisoCheckout" style="margin-bottom:14px;padding:10px 12px;background:#fffbeb;color:#92400e;border:1px solid #fde68a;border-radius:10px;font-size:13px">\r
      {{ avisoCheckout }}\r
    </div>\r
\r
    <div *ngIf="paso === 'resumen'" style="display:grid;grid-template-columns:2fr 1fr;gap:16px;align-items:start">\r
      <div style="background:white;border:1px solid #e2e8f0;border-radius:16px;padding:18px">\r
        <h2 style="margin:0 0 12px;font-size:18px;color:#0f172a">{{ 'CHECKOUT.CART_TITLE' | translate }}</h2>\r
\r
        <div *ngIf="carritoItems.length === 0" style="padding:22px;border:1px dashed #cbd5e1;border-radius:12px;color:#64748b;text-align:center">\r
          {{ 'CHECKOUT.EMPTY' | translate }}\r
        </div>\r
\r
        <div *ngIf="carritoItems.length > 0" style="display:grid;gap:12px">\r
          <div *ngFor="let item of carritoItems" style="border:1px solid #e2e8f0;border-radius:12px;padding:12px;display:flex;justify-content:space-between;gap:10px;align-items:flex-start">\r
            <div>\r
              <p style="margin:0;font-weight:700;color:#0f172a">{{ item.nombre }}</p>\r
              <p style="margin:4px 0 8px;font-size:12px;color:#64748b">{{ item.categoria }} \xB7 {{ item.precio | bolivianos }}</p>\r
              <div style="display:flex;align-items:center;gap:8px">\r
                <button type="button" (click)="decrementarCantidad(item)" style="width:28px;height:28px;border:1px solid #cbd5e1;border-radius:999px;background:white;cursor:pointer">-</button>\r
                <span style="min-width:20px;text-align:center;font-weight:700">{{ item.cantidad }}</span>\r
                <button type="button" (click)="incrementarCantidad(item)" style="width:28px;height:28px;border:1px solid #cbd5e1;border-radius:999px;background:white;cursor:pointer">+</button>\r
              </div>\r
            </div>\r
            <div style="display:flex;flex-direction:column;align-items:flex-end;gap:8px">\r
              <span style="font-weight:700;color:#1D9E75">{{ item.precio * item.cantidad | bolivianos }}</span>\r
              <button type="button" (click)="quitarDelCarrito(item)" style="border:none;background:#fee2e2;color:#b91c1c;padding:6px 10px;border-radius:8px;cursor:pointer">\r
                {{ 'CHECKOUT.REMOVE' | translate }}\r
              </button>\r
            </div>\r
          </div>\r
        </div>\r
      </div>\r
\r
      <div style="background:white;border:1px solid #e2e8f0;border-radius:16px;padding:18px;position:sticky;top:16px">\r
        <h3 style="margin:0 0 12px;font-size:16px;color:#0f172a">{{ 'CHECKOUT.SUMMARY' | translate }}</h3>\r
\r
        <label for="checkout-direccion" style="display:block;font-size:13px;color:#334155;margin-bottom:6px">{{ 'CHECKOUT.DELIVERY_ADDRESS_LABEL' | translate }}</label>\r
        <!--map-picker -->\r
        <button type="button" (click)="toggleMapa()"\r
                style="width:100%;margin-bottom:8px;padding:8px;border:1px dashed #1D9E75;background:#f0fdf4;\r
         color:#166534;border-radius:10px;cursor:pointer;font-size:13px">\r
          \u{1F5FA}\uFE0F {{ mostrarMapa ? 'Cerrar mapa' : 'Seleccionar ubicaci\xF3n en mapa' }}\r
        </button>\r
\r
        <div *ngIf="mostrarMapa" style="margin-bottom:10px">\r
          <app-map-picker (locationSelected)="onLocationSelected($event)" />\r
        </div>\r
        <!--map-picker-->\r
        <textarea id="checkout-direccion" [(ngModel)]="direccionEntrega" (ngModelChange)="validarCoberturaDireccion()" rows="2" [placeholder]="'CHECKOUT.DELIVERY_ADDRESS_PLACEHOLDER' | translate"\r
                  style="width:100%;box-sizing:border-box;resize:vertical;padding:10px;border:1px solid #cbd5e1;border-radius:10px;font-family:inherit;font-size:13px"></textarea>\r
\r
        <label for="checkout-referencia" style="display:block;font-size:13px;color:#334155;margin:10px 0 6px">{{ 'CHECKOUT.DELIVERY_REFERENCE_LABEL' | translate }}</label>\r
        <input id="checkout-referencia" [(ngModel)]="referenciaEntrega" [placeholder]="'CHECKOUT.DELIVERY_REFERENCE_PLACEHOLDER' | translate"\r
               style="width:100%;box-sizing:border-box;padding:10px;border:1px solid #cbd5e1;border-radius:10px;font-family:inherit;font-size:13px" />\r
\r
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-top:10px">\r
          <input id="checkout-lat" [(ngModel)]="latEntrega" type="number" step="any"\r
                 [placeholder]="'CHECKOUT.DELIVERY_LAT_PLACEHOLDER' | translate" readonly\r
                 style="width:100%;box-sizing:border-box;padding:10px;border:1px solid #cbd5e1;\r
           border-radius:10px;font-family:inherit;font-size:13px;background:#f8fafc" />\r
          <input id="checkout-lng" [(ngModel)]="lngEntrega" type="number" step="any"\r
                 [placeholder]="'CHECKOUT.DELIVERY_LNG_PLACEHOLDER' | translate" readonly\r
                 style="width:100%;box-sizing:border-box;padding:10px;border:1px solid #cbd5e1;\r
           border-radius:10px;font-family:inherit;font-size:13px;background:#f8fafc" />\r
        </div>\r
\r
        <p *ngIf="coberturaValida" style="margin:10px 0 0;padding:8px 10px;background:#dcfce7;color:#166534;border-radius:8px;font-size:12px">\r
          {{ 'CHECKOUT.COVERAGE_OK' | translate:{ zona: zonaCoberturaDetectada } }}\r
        </p>\r
        <p *ngIf="direccionEntrega && !coberturaValida && !errorCobertura" style="margin:10px 0 0;padding:8px 10px;background:#fef2f2;color:#b91c1c;border-radius:8px;font-size:12px">\r
          {{ 'CHECKOUT.COVERAGE_FAIL' | translate }}\r
        </p>\r
        <div *ngIf="direccionEntrega && !coberturaValida" style="margin-top:8px">\r
          <button type="button" (click)="cambiarDireccion()" style="border:1px solid #d1d5db;background:white;color:#334155;border-radius:8px;padding:6px 10px;font-size:12px;cursor:pointer">\r
            {{ 'CHECKOUT.COVERAGE_EDIT_CTA' | translate }}\r
          </button>\r
        </div>\r
        <p *ngIf="errorCobertura" style="margin:10px 0 0;padding:8px 10px;background:#fef2f2;color:#b91c1c;border-radius:8px;font-size:12px">\r
          {{ errorCobertura }}\r
        </p>\r
        <p *ngIf="!coberturaValida && sugerenciasCobertura.length > 0" style="margin:6px 0 0;font-size:12px;color:#64748b">\r
          {{ 'CHECKOUT.COVERAGE_SUGGESTIONS' | translate:{ zonas: sugerenciasCobertura.join(', ') } }}\r
        </p>\r
\r
        <label for="checkout-nota" style="display:block;font-size:13px;color:#334155;margin-bottom:6px">{{ 'CHECKOUT.NOTES_LABEL' | translate }}</label>\r
        <textarea id="checkout-nota" [(ngModel)]="notaPedido" rows="3" [placeholder]="'CHECKOUT.NOTES_PLACEHOLDER' | translate"\r
                  style="width:100%;box-sizing:border-box;resize:vertical;padding:10px;border:1px solid #cbd5e1;border-radius:10px;font-family:inherit;font-size:13px"></textarea>\r
        <div style="display:flex;justify-content:space-between;align-items:center;margin:14px 0 10px">\r
          <span style="font-size:13px;color:#64748b">{{ 'CHECKOUT.ITEMS_TOTAL' | translate:{ count: cantidadCarrito } }}</span>\r
          <span style="font-weight:700;color:#0f172a">{{ totalCarrito | bolivianos }}</span>\r
        </div>\r
        <button type="button" (click)="continuarAConfirmacion()" [disabled]="carritoItems.length === 0"\r
                style="width:100%;border:none;background:#1D9E75;color:white;border-radius:10px;padding:12px 14px;font-weight:700;cursor:pointer">\r
          {{ 'CHECKOUT.CONTINUE' | translate }}\r
        </button>\r
      </div>\r
    </div>\r
\r
    <div *ngIf="paso === 'confirmacion'" style="max-width:720px;margin:0 auto;background:white;border:1px solid #e2e8f0;border-radius:16px;padding:20px">\r
      <h2 style="margin:0 0 14px;color:#0f172a">{{ 'CHECKOUT.CONFIRM_TITLE' | translate }}</h2>\r
      <div style="display:grid;gap:10px;margin-bottom:16px">\r
        <div style="padding:12px;border-radius:10px;background:#f8fafc">\r
          <p style="margin:0;font-size:12px;color:#64748b">{{ 'CHECKOUT.CLIENT' | translate }}</p>\r
          <p style="margin:4px 0 0;font-weight:700">{{ nombreUsuario }}</p>\r
          <p style="margin:2px 0 0;font-size:13px;color:#334155">{{ emailUsuario }}</p>\r
        </div>\r
        <div style="padding:12px;border-radius:10px;background:#f8fafc">\r
          <p style="margin:0;font-size:12px;color:#64748b">{{ 'CHECKOUT.ORDER_TOTAL' | translate }}</p>\r
          <p style="margin:4px 0 0;font-size:20px;font-weight:800;color:#1D9E75">{{ totalCarrito | bolivianos }}</p>\r
          <p style="margin:4px 0 0;font-size:12px;color:#64748b">{{ cantidadCarrito }} {{ 'CHECKOUT.ITEMS' | translate }}</p>\r
        </div>\r
        <div *ngIf="notaPedido" style="padding:12px;border-radius:10px;background:#f8fafc">\r
          <p style="margin:0;font-size:12px;color:#64748b">{{ 'CHECKOUT.NOTES_LABEL' | translate }}</p>\r
          <p style="margin:4px 0 0;font-size:13px;color:#0f172a">{{ notaPedido }}</p>\r
        </div>\r
        <div style="padding:12px;border-radius:10px;background:#f8fafc">\r
          <p style="margin:0;font-size:12px;color:#64748b">{{ 'CHECKOUT.DELIVERY_ADDRESS_LABEL' | translate }}</p>\r
          <p style="margin:4px 0 0;font-size:13px;color:#0f172a">{{ direccionEntrega }}</p>\r
          <p *ngIf="referenciaEntrega" style="margin:4px 0 0;font-size:12px;color:#334155">{{ referenciaEntrega }}</p>\r
          <p *ngIf="latEntregaNumero !== undefined && lngEntregaNumero !== undefined" style="margin:4px 0 0;font-size:12px;color:#334155">Lat: {{ latEntregaNumero }} \xB7 Lng: {{ lngEntregaNumero }}</p>\r
          <p *ngIf="zonaCoberturaDetectada" style="margin:6px 0 0;font-size:12px;color:#166534">{{ 'CHECKOUT.COVERAGE_OK' | translate:{ zona: zonaCoberturaDetectada } }}</p>\r
        </div>\r
      </div>\r
\r
      <div *ngIf="!coberturaValida" style="margin-bottom:12px;padding:10px 12px;background:#fef2f2;color:#b91c1c;border:1px solid #fecaca;border-radius:10px;font-size:13px;display:flex;justify-content:space-between;align-items:center;gap:8px">\r
        <span>{{ 'CHECKOUT.COVERAGE_FAIL' | translate }}</span>\r
        <button type="button" (click)="cambiarDireccion()" style="border:1px solid #d1d5db;background:white;color:#334155;border-radius:8px;padding:6px 10px;font-size:12px;cursor:pointer">\r
          {{ 'CHECKOUT.COVERAGE_EDIT_CTA' | translate }}\r
        </button>\r
      </div>\r
\r
      <div style="display:flex;justify-content:flex-end;gap:10px">\r
        <button type="button" (click)="volverAResumen()" [disabled]="procesandoPedido"\r
                style="border:1px solid #d1d5db;background:white;color:#334155;border-radius:10px;padding:10px 14px;cursor:pointer">\r
          {{ 'CHECKOUT.BACK' | translate }}\r
        </button>\r
        <button type="button" (click)="confirmarPedido()" [disabled]="!puedeConfirmarPedido"\r
                style="border:none;background:#1D9E75;color:white;border-radius:10px;padding:10px 16px;font-weight:700;cursor:pointer;min-width:180px">\r
          {{ procesandoPedido ? ('CHECKOUT.PROCESSING' | translate) : ('CHECKOUT.CONFIRM_ORDER' | translate) }}\r
        </button>\r
      </div>\r
    </div>\r
\r
    <div *ngIf="paso === 'resultado'" style="max-width:560px;margin:0 auto;background:white;border:1px solid #dcfce7;border-radius:18px;padding:24px;text-align:center">\r
      <div style="width:56px;height:56px;background:#dcfce7;color:#166534;border-radius:999px;display:flex;align-items:center;justify-content:center;font-size:26px;margin:0 auto 12px">\u2713</div>\r
      <h2 style="margin:0 0 8px;color:#0f172a">{{ 'CHECKOUT.SUCCESS_TITLE' | translate }}</h2>\r
      <p style="margin:0 0 6px;color:#334155">{{ 'CHECKOUT.SUCCESS_MESSAGE' | translate }}</p>\r
      <p style="margin:0 0 8px;font-size:18px;font-weight:700;color:#1D9E75">{{ pedidoCreado?.numero }}</p>\r
      <p style="margin:0 0 12px;font-size:13px;color:#64748b">{{ 'CHECKOUT.PAY_INSTRUCTIONS' | translate }}</p>\r
\r
      <div *ngIf="!pagoConfirmado" style="margin:0 auto 12px;max-width:420px;padding:10px 12px;background:#fffbeb;border-radius:10px;border:1px solid #fde68a;color:#92400e;font-size:12px">\r
        {{ 'CHECKOUT.PAYMENT_PENDING_NOTICE' | translate }}\r
      </div>\r
\r
      <div *ngIf="!pagoConfirmado && esperandoConfirmacionPago" style="margin:0 auto 12px;max-width:420px;padding:10px 12px;background:#eff6ff;border-radius:10px;border:1px solid #bfdbfe;color:#1d4ed8;font-size:12px">\r
        {{ 'CHECKOUT.PAYMENT_WAITING_CONFIRMATION' | translate }}\r
      </div>\r
\r
      <div *ngIf="qrPagoUrl" style="display:flex;justify-content:center;margin-bottom:10px">\r
        <img [src]="qrPagoUrl" [alt]="'CHECKOUT.QR_ALT' | translate" style="width:220px;height:220px;border-radius:12px;border:1px solid #e2e8f0;padding:8px;background:white" />\r
      </div>\r
\r
      <div style="margin:0 auto 16px;max-width:420px;padding:10px 12px;background:#f8fafc;border-radius:10px;border:1px solid #e2e8f0">\r
        <p style="margin:0 0 4px;font-size:12px;color:#64748b">{{ 'CHECKOUT.PAY_REFERENCE' | translate }}</p>\r
        <p style="margin:0;font-size:12px;font-family:Consolas,monospace;word-break:break-all;color:#0f172a">{{ referenciaPago }}</p>\r
      </div>\r
\r
      <div style="display:flex;justify-content:center;gap:10px;flex-wrap:wrap">\r
\r
        <!-- \u2500\u2500 MODO MOCK: bot\xF3n "Simular pago y confirmar" (sin URL externa) \u2500\u2500 -->\r
        <button *ngIf="esMock && !pagoConfirmado" type="button" (click)="confirmarPagoManual()"\r
                [disabled]="confirmandoPago"\r
                [style]="confirmandoPago\r
                  ? 'display:flex;align-items:center;gap:8px;border:1px solid #d1d5db;background:#f8fafc;color:#94a3b8;border-radius:10px;padding:10px 18px;font-weight:700;cursor:not-allowed;font-size:14px'\r
                  : 'display:flex;align-items:center;gap:8px;border:none;background:#0f172a;color:white;border-radius:10px;padding:10px 18px;font-weight:700;cursor:pointer;font-size:14px'">\r
          <svg width="15" height="15" viewBox="0 0 24 24" fill="none"\r
               [attr.stroke]="confirmandoPago ? '#94a3b8' : 'white'" stroke-width="2.5">\r
            <polyline points="20 6 9 17 4 12"/>\r
          </svg>\r
          {{ confirmandoPago ? ('CHECKOUT.PROCESSING' | translate) : ('CHECKOUT.CONFIRM_PAYMENT' | translate) }}\r
        </button>\r
\r
        <!-- \u2500\u2500 MODO REAL: bot\xF3n "Pagar ahora" solo si hay URL real Y pago pendiente \u2500\u2500 -->\r
        <button *ngIf="!esMock && pagoUrl && !pagoConfirmado" type="button" (click)="abrirPagoExterno()"\r
                style="display:flex;align-items:center;gap:8px;border:none;background:#2563eb;color:white;border-radius:10px;padding:10px 18px;font-weight:700;cursor:pointer;font-size:14px">\r
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="white" stroke-width="2">\r
            <rect x="1" y="4" width="22" height="16" rx="2"/><line x1="1" y1="10" x2="23" y2="10"/>\r
          </svg>\r
          {{ 'CHECKOUT.PAY_NOW' | translate }}\r
        </button>\r
\r
        <!-- \u2500\u2500 MODO REAL: "Ya pagu\xE9, confirmar" despu\xE9s de pagar en la URL externa \u2500\u2500 -->\r
        <button *ngIf="!esMock && !pagoConfirmado" type="button" (click)="confirmarPagoManual()"\r
                [disabled]="confirmandoPago"\r
                [style]="confirmandoPago\r
                  ? 'display:flex;align-items:center;gap:8px;border:1px solid #d1d5db;background:#f8fafc;color:#94a3b8;border-radius:10px;padding:10px 18px;font-weight:700;cursor:not-allowed;font-size:14px'\r
                  : 'display:flex;align-items:center;gap:8px;border:none;background:#0f172a;color:white;border-radius:10px;padding:10px 18px;font-weight:700;cursor:pointer;font-size:14px'">\r
          <svg width="15" height="15" viewBox="0 0 24 24" fill="none"\r
               [attr.stroke]="confirmandoPago ? '#94a3b8' : 'white'" stroke-width="2.5">\r
            <polyline points="20 6 9 17 4 12"/>\r
          </svg>\r
          {{ confirmandoPago ? ('CHECKOUT.PROCESSING' | translate) : ('CHECKOUT.CONFIRM_PAYMENT' | translate) }}\r
        </button>\r
\r
        <!-- \u2500\u2500 RASTREAR PEDIDO: siempre visible, verde cuando pago confirmado \u2500\u2500 -->\r
        <button type="button" (click)="rastrearPedido()" [disabled]="rastreandoPedido"\r
                [style]="pagoConfirmado\r
                  ? 'display:flex;align-items:center;gap:8px;border:none;background:#1D9E75;color:white;border-radius:10px;padding:10px 20px;font-weight:700;cursor:pointer;font-size:14px'\r
                  : 'display:flex;align-items:center;gap:8px;border:1px solid #1D9E75;background:white;color:#1D9E75;border-radius:10px;padding:10px 20px;font-weight:700;cursor:pointer;font-size:14px'">\r
          <svg *ngIf="!rastreandoPedido" width="16" height="16" viewBox="0 0 24 24" fill="none"\r
               [attr.stroke]="pagoConfirmado ? 'white' : '#1D9E75'" stroke-width="2">\r
            <circle cx="11" cy="11" r="8"/><path d="m21 21-4.35-4.35"/>\r
          </svg>\r
          <svg *ngIf="rastreandoPedido" width="16" height="16" viewBox="0 0 24 24" fill="none"\r
               [attr.stroke]="pagoConfirmado ? 'white' : '#1D9E75'" stroke-width="2"\r
               style="animation:spin 0.8s linear infinite">\r
            <circle cx="12" cy="12" r="10" stroke-dasharray="31.4" stroke-dashoffset="10"/>\r
          </svg>\r
          {{ rastreandoPedido ? 'Confirmando...' : 'Rastrear pedido' }}\r
        </button>\r
\r
      </div>\r
    </div>\r
  </div>\r
</div>\r
` }]
  }], null, null);
})();
